var b="url",c="采购单审核：需求采购.html",d="generationDate",e=new Date(1781592921422.74),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="aebcef64214f47e993a3352cd128fc50",u="type",v="Axure:Page",w="采购单审核：需求采购",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="ba3b195858d9419fb7edf5a76ec74cbf",D="label",E="未下发数",F="说明",G="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">其它详情页(有单号)</span><span>：实时查询，取需求物料行对应的 </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#02A7F0;\">“当前需求数量”-</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">除当前订单号外的</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#02A7F0;\">“下发采购数量</span><span style=\"color:#02A7F0;\">(已排除'已作废'状态数量)”</span></p>",H="2",I="f14c7d932b674edea19b0ff08f7198c6",J="合同条款：",K="<p><span>1.点击后查询对应选中的合同在[基础数据系统：合同模板]中数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.合同模板不存在：Toast提示“当前合同模板已被删除”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.合同模板存在：弹窗展示对应合同的的“合同条款”</span></p>",L="3",M="c1d99c91dc6b4c2d8d112d8034a1a665",N="采购数量",O="<p><span>若当前数值大于对应行的'未下发数'，数值标红</span></p>",P="4",Q="f2c3431c1fcf4ebe9e07e79d29763baa",R="含税单价",S="<p><span>若当前数值大于对应行的'需求单价'，数值标红</span></p>",T="5",U="8280d2a877034d4f9378b95f3f6ed9e0",V="含税总额.",W="<p><span>若当前数值大于对应行的'需求总额'，数值标红</span></p>",X="6",Y="15cd314f839a46759bbb60343b84ee10",Z="通过",ba="<p><span>1.按钮展示/隐藏：跟随单据状态</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">待审核</span><span>：展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.新增、</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">待提交、待操作、被退回、已作废、已结案</span><span>：隐藏</span></p><p><span>2.弹窗二次确认后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.单据状态变更为“已通过”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.记录审核备注、审核人及审核时间</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.页面跳转至列表页</span></p>",bb="7",bc="23736951b8c24db7bc4092bdf25da596",bd="退回",be="<p><span>1.按钮展示/隐藏：跟随单据状态</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">待审核、待操作</span><span>：展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.新增、</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">待提交、被退回、已作废、已结案</span><span>：隐藏</span></p><p><span>2.弹窗二次确认后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.单据状态变更为“被退回”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.记录审核备注、审核人及审核时间</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.页面跳转至列表页</span></p>",bf="8",bg="96492fd4e3674e8da4928e184f001e40",bh="确定",bi="<p><span>1.将审核结果变更至对应采购订单(WLCG)的“状态”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.通过：待操作</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.退回：已退回</span></p><p><span>2.覆盖当前审核人、审核时间及审核备注至采购订单(WLCG)中</span></p><p><span>3.返回至列表页</span></p>",bj="style",bk="baseStyle",bl="627587b6038d43cca051c114ac41ad32",bm="pageAlignment",bn="center",bo="fill",bp="fillType",bq="solid",br="color",bs=0xFFFFFFFF,bt="image",bu="imageAlignment",bv="near",bw="imageRepeat",bx="auto",by="favicon",bz="sketchFactor",bA="0",bB="colorStyle",bC="appliedColor",bD="fontName",bE="Applied Font",bF="borderWidth",bG="borderVisibility",bH="borderFill",bI=0xFF797979,bJ="cornerRadius",bK="cornerVisibility",bL="outerShadow",bM="on",bN=false,bO="offsetX",bP=5,bQ="offsetY",bR="blurRadius",bS="spread",bT="r",bU=0,bV="g",bW="b",bX="a",bY=0.349019607843137,bZ="adaptiveStyles",ca="interactionMap",cb="diagram",cc="objects",cd="id",ce="89a21f33649e4cf8a66ac828242c4443",cf="friendlyType",cg="标题-1420",ch="referenceDiagramObject",ci="styleType",cj="visible",ck=true,cl=1420